contracts/BurnTracker.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract BurnTracker {
    struct UserStats {
        uint256 totalGasUsed;
        uint256 totalTransactions;
        uint256 avaxBurned;
    }

    mapping(address => UserStats) public userStats;

    event GasTracked(address user, uint256 gasUsed, uint256 txCount);

    function recordUsage(address user, uint256 gasUsed, uint256 txCount) external {
        UserStats storage stats = userStats[user];
        stats.totalGasUsed += gasUsed;
        stats.totalTransactions += txCount;
        stats.avaxBurned += gasUsed * 25 gwei;
        emit GasTracked(user, gasUsed, txCount);
    }

    function getMyStats() external view returns (UserStats memory) {
        return userStats[msg.sender];
    }
}

contracts/DCAFactory.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "./DCAVault.sol";
import "./ExecutionEngine.sol";

contract DCAFactory {

    address public owner;
    address public executionEngine;
    address public burnTracker;

    address[] public allVaults;
    mapping(address => address) public userVault;

    event VaultCreated(address indexed user, address indexed vault);
    event ExecutionEngineSet(address indexed executionEngine);
    event BurnTrackerSet(address indexed burnTracker);
    event DCATriggered(address indexed vault, address indexed user);

    modifier onlyOwner() {
        require(msg.sender == owner, "Not owner");
        _;
    }

    constructor() {
        owner = msg.sender;
    }

    function setBurnTracker(address _burnTracker) external onlyOwner {
        require(_burnTracker != address(0), "Zero address");
        require(burnTracker == address(0), "Already set");
        burnTracker = _burnTracker;
        emit BurnTrackerSet(_burnTracker);
    }

    function setExecutionEngine(address _executionEngine) external onlyOwner {
        require(_executionEngine != address(0), "Zero address");
        require(executionEngine == address(0), "Already set");
        executionEngine = _executionEngine;
        emit ExecutionEngineSet(_executionEngine);
    }

    function createVault(uint256 _buyAmount, uint256 _frequency) external returns (address) {
        require(userVault[msg.sender] == address(0), "Vault already exists");
        require(_buyAmount > 0, "Buy amount is zero");
        require(_frequency > 0, "Frequency is zero");

        DCAVault vault = new DCAVault(msg.sender);
        vault.initialize(_buyAmount, _frequency);

        userVault[msg.sender] = address(vault);
        allVaults.push(address(vault));

        emit VaultCreated(msg.sender, address(vault));
        return address(vault);
    }

    function getMyVault() external view returns (address) {
        return userVault[msg.sender];
    }

    function getAllVaults() external view returns (address[] memory) {
        return allVaults;
    }

    function triggerDCA(address user) external {
        require(executionEngine != address(0), "ExecutionEngine not set");
        address payable vault = payable(userVault[user]);
        require(vault != address(0), "No vault for user");
        require(DCAVault(vault).canExecute(), "Too soon to execute");

        ExecutionEngine(executionEngine).executeDCA(vault);
        emit DCATriggered(vault, user);
    }

    function triggerBatchDCA(address[] calldata users) external {
        require(executionEngine != address(0), "ExecutionEngine not set");
        require(users.length > 0, "Empty list");

        address[] memory vaults = new address[](users.length);
        uint256 count = 0;

        for (uint256 i = 0; i < users.length;) {
            address payable vault = payable(userVault[users[i]]);
            if (vault != address(0) && DCAVault(vault).canExecute()) {
                vaults[count] = address(vault);
                unchecked { ++count; }
            }
            unchecked { ++i; }
        }

        require(count > 0, "No vaults ready");

        assembly { mstore(vaults, count) }

        ExecutionEngine(executionEngine).executeBatch(vaults);
    }
}

contracts/DCAVault.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

contract DCAVault is ReentrancyGuard {
    using SafeERC20 for IERC20;

    address public owner;
    address public factory;
    uint256 public buyAmount;
    uint256 public frequency;
    uint256 public lastExecution;
    uint256 public totalInvested;
    uint256 public executionCount;
    bool public active;

    event DCAExecuted(uint256 amountSpent, uint256 timestamp);
    event Withdrawn(address indexed token, uint256 amount);
    event VaultPaused();
    event VaultResumed();

    modifier onlyFactory() { require(msg.sender == factory, "Only factory"); _; }
    modifier onlyOwner()   { require(msg.sender == owner,   "Only owner");   _; }

    constructor(address _owner) {
        require(_owner != address(0), "Invalid owner");
        owner   = _owner;
        factory = msg.sender;
        active  = true;
    }

    function initialize(uint256 _buyAmount, uint256 _frequency) external onlyFactory {
        require(_buyAmount > 0, "Invalid buy amount");
        require(_frequency > 0, "Invalid frequency");
        require(buyAmount == 0, "Already initialized");
        buyAmount     = _buyAmount;
        frequency     = _frequency;
        lastExecution = block.timestamp;
    }

    // Needed by DCAFactory.triggerDCA and triggerBatchDCA
    function canExecute() external view returns (bool) {
        return active && block.timestamp >= lastExecution + frequency;
    }

    function executeDCA() external onlyFactory nonReentrant returns (bool) {
        require(active, "Vault is paused");
        require(block.timestamp >= lastExecution + frequency, "Too soon");
        executionCount++;
        lastExecution  = block.timestamp;
        totalInvested += buyAmount;
        emit DCAExecuted(buyAmount, block.timestamp);
        return true;
    }

    function pause()  external onlyOwner { require(active,  "Already paused");  active = false; emit VaultPaused();  }
    function resume() external onlyOwner { require(!active, "Already active");  active = true;  emit VaultResumed(); }

    function updateSettings(uint256 _buyAmount, uint256 _frequency) external onlyOwner {
        require(_buyAmount > 0, "Invalid buy amount");
        require(_frequency > 0, "Invalid frequency");
        buyAmount = _buyAmount;
        frequency = _frequency;
    }

    function withdraw(address token, uint256 amount) external onlyOwner nonReentrant {
        require(amount > 0, "Amount must be positive");
        require(IERC20(token).balanceOf(address(this)) >= amount, "Insufficient balance");
        IERC20(token).safeTransfer(owner, amount);
        emit Withdrawn(token, amount);
    }

    function withdrawAVAX(uint256 amount) external onlyOwner nonReentrant {
        require(amount > 0, "Amount must be positive");
        require(address(this).balance >= amount, "Insufficient AVAX");
        (bool success, ) = payable(owner).call{value: amount}("");
        require(success, "AVAX transfer failed");
        emit Withdrawn(address(0), amount);
    }

    function getStatus() external view returns (
        uint256 _buyAmount, uint256 _frequency, uint256 _lastExecution,
        uint256 _nextExecution, uint256 _totalInvested, uint256 _executionCount,
        bool _active, bool _canExecute
    ) {
        return (buyAmount, frequency, lastExecution, lastExecution + frequency,
                totalInvested, executionCount, active,
                active && block.timestamp >= lastExecution + frequency);
    }

    receive() external payable {}
}

contracts/ExecutionEngine.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "./DCAVault.sol";
import "./BurnTracker.sol";
import "./interfaces/ITraderJoe.sol";
import "./interfaces/IBenqi.sol";

contract ExecutionEngine is ReentrancyGuard {
    using SafeERC20 for IERC20;

    // State
    address public factory;
    BurnTracker public burnTracker;
    bool public factoryLocked;

    // Avalanche Mainnet Addresses
    address public constant USDC         = 0xB97EF9Ef8734C71904D8002F8b6Bc66Dd9c48a6E;
    address public constant WAVAX        = 0xB31f66AA3C1e785363F0875A1B74E27b85FD66c7;
    address public constant LB_ROUTER    = 0x9A93a421b74F1c5755b83dD2C211614dC419C44b;
    address public constant BENQI_qiAVAX = 0x5c0401e81e6953a22c95311bc54060BDE84b1022;

    uint256 public constant SLIPPAGE  = 100;
    uint256 public constant PRECISION = 10000;

    // Events
    event DCAExecuted(
        address indexed vault,
        address indexed user,
        uint256 usdcSpent,
        uint256 avaxReceived,
        uint256 qiTokens
    );
    event DCAFailed(address indexed vault, bytes reason);
    event FactoryUpdated(address indexed oldFactory, address indexed newFactory);

    // Modifiers
    modifier onlyFactory() {
        require(msg.sender == factory, "Only factory");
        _;
    }

    // Constructor
    constructor(address _burnTracker) {
        require(_burnTracker != address(0), "Invalid BurnTracker");
        factory       = msg.sender;
        burnTracker   = BurnTracker(_burnTracker);
        factoryLocked = false;
    }

    // setFactory
    // Called ONCE by deployment script after DCAFactory is deployed.
    // Locks permanently — can never be changed again after first call.
    function setFactory(address _factory) external {
        require(_factory != address(0), "Zero address");
        require(msg.sender == factory,  "Not authorized");
        require(!factoryLocked,         "Factory already locked");
        address old   = factory;
        factory       = _factory;
        factoryLocked = true;
        emit FactoryUpdated(old, _factory);
    }

    // Single Vault Execution
function executeDCA(address vault) external onlyFactory nonReentrant returns (bool) {
    uint256 gasStart   = gasleft();
    uint256 buyAmount;
    address vaultOwner;
    DCAVault dcaVault;

    {
        dcaVault = DCAVault(payable(vault));
        buyAmount  = dcaVault.buyAmount();
        vaultOwner = dcaVault.owner();
        require(buyAmount > 0, "Buy amount is zero");
    }

    IERC20 usdc = IERC20(USDC);
    usdc.safeTransferFrom(vaultOwner, address(this), buyAmount);
    usdc.forceApprove(LB_ROUTER, buyAmount);

    ILBRouter.Path memory path;
    path.pairBinSteps    = new uint256[](1);
    path.pairBinSteps[0] = 20;
    path.tokenPath       = new address[](2);
    path.tokenPath[0]    = USDC;
    path.tokenPath[1]    = WAVAX;

    uint256 amountOutMin = (buyAmount * (PRECISION - SLIPPAGE)) / PRECISION;

    uint256 avaxReceived = ILBRouter(LB_ROUTER).swapExactTokensForTokens(
        buyAmount,
        amountOutMin,
        path,
        address(this),
        block.timestamp + 300
    );
    require(avaxReceived > 0, "Swap returned zero");

    IERC20 wavax = IERC20(WAVAX);
    wavax.forceApprove(BENQI_qiAVAX, avaxReceived);

    IERC20 qiToken = IERC20(BENQI_qiAVAX);
    uint256 qiBefore  = qiToken.balanceOf(address(this));
    uint256 mintError = IBenqiToken(BENQI_qiAVAX).mint(avaxReceived);
    require(mintError == 0, "Benqi mint failed");
    uint256 qiTokens  = qiToken.balanceOf(address(this)) - qiBefore;
    require(qiTokens > 0, "No qiTokens received");

    qiToken.safeTransfer(vault, qiTokens);
    dcaVault.executeDCA();

    uint256 gasUsed = gasStart - gasleft();
    burnTracker.recordUsage(vaultOwner, gasUsed, 1);

    emit DCAExecuted(vault, vaultOwner, buyAmount, avaxReceived, qiTokens);
    return true;
}

    // Batch Execution
    function executeBatch(address[] calldata vaults) external onlyFactory {
        require(vaults.length > 0, "Empty list");
        for (uint256 i = 0; i < vaults.length;) {
            try this._executeInternal(vaults[i]) {
            } catch (bytes memory reason) {
                emit DCAFailed(vaults[i], reason);
            }
            unchecked { ++i; }
        }
    }

    // External for try/catch — self-calls only
    function _executeInternal(address vault) external nonReentrant {
        require(msg.sender == address(this), "Internal only");

        uint256 gasStart;
        uint256 buyAmount;
        address vaultOwner;
        DCAVault dcaVault;

        {
            dcaVault = DCAVault(payable(vault));
            gasStart   = gasleft();
            buyAmount  = dcaVault.buyAmount();
            vaultOwner = dcaVault.owner();
            require(buyAmount > 0, "Buy amount is zero");
        }

        IERC20 usdc = IERC20(USDC);
        usdc.safeTransferFrom(vaultOwner, address(this), buyAmount);
        usdc.forceApprove(LB_ROUTER, buyAmount);

        ILBRouter.Path memory path;
        path.pairBinSteps    = new uint256[](1);
        path.pairBinSteps[0] = 20;
        path.tokenPath       = new address[](2);
        path.tokenPath[0]    = USDC;
        path.tokenPath[1]    = WAVAX;

        uint256 amountOutMin = (buyAmount * (PRECISION - SLIPPAGE)) / PRECISION;

        uint256 avaxReceived = ILBRouter(LB_ROUTER).swapExactTokensForTokens(
            buyAmount, amountOutMin, path, address(this), block.timestamp + 300
        );
        require(avaxReceived > 0, "Swap returned zero");

        IERC20 wavax = IERC20(WAVAX);
        wavax.forceApprove(BENQI_qiAVAX, avaxReceived);

        IERC20 qiToken = IERC20(BENQI_qiAVAX);
        uint256 qiBefore  = qiToken.balanceOf(address(this));
        uint256 mintError = IBenqiToken(BENQI_qiAVAX).mint(avaxReceived);
        require(mintError == 0, "Benqi mint failed");
        uint256 qiTokens  = qiToken.balanceOf(address(this)) - qiBefore;
        require(qiTokens > 0, "No qiTokens received");

        qiToken.safeTransfer(vault, qiTokens);
        dcaVault.executeDCA();

        uint256 gasUsed = gasStart - gasleft();
        burnTracker.recordUsage(vaultOwner, gasUsed, 1);

        emit DCAExecuted(vault, vaultOwner, buyAmount, avaxReceived, qiTokens);
    }

    //View Helpers
    function isReady() external view returns (bool) {
        return factoryLocked && factory != address(0);
    }

    function getConfig() external view returns (
        address _factory,
        address _burnTracker,
        bool    _factoryLocked
    ) {
        return (factory, address(burnTracker), factoryLocked);
    }
}

